export function capitalize(str){if(!str)return '';return str.charAt(0).toUpperCase()+str.slice(1);}export function getInitials(name){if(!name)return '';return name .split(' ').map(n=>n[0]).join('').toUpperCase().slice(0,2);}export function slugify(str){if(!str)return '';return str .toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^đàáảãạăằắẳẵặâầấẩẫậèéẻẽẹêềếểễệìíỉĩịòóỏõọôồốổỗộơờớởỡợùúủũụưừứửữựỳýỷỹỵđ]/g,'').replace(/đ/g,'d').replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)+/g,'');}export{truncate}from '../shared/format-utils.js';export function escapeHTML(str){if(!str)return '';const div=document.createElement('div');div.textContent=str;return div.innerHTML;}export function parseQuery(url){const queryString=url.split('?')[1];if(!queryString)return{};return queryString.split('&').reduce((params,pair)=>{const [key,value]=pair.split('=');params[decodeURIComponent(key)]=decodeURIComponent(value||'');return params;},{});}